import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"AppLovin","description":"","frontmatter":{"title":"AppLovin","slug":"applovin"},"headers":[],"relativePath":"marketer-hub/applovin.md","filePath":"marketer-hub/applovin.md"}'),i={name:"marketer-hub/applovin.md"};function o(s,e,p,l,d,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>.png &quot;AppLovin-logo.png&quot;)</p><p><a href="https://www.applovin.com" target="_blank" rel="noreferrer">AppLovin&#39;s</a> marketing platform provides marketing automation and analytics for brands that want to reach new consumers on mobile.</p><p><strong>PARTNER CAPABILITIES</strong></p><table tabindex="0"><thead><tr><th>Partner Capabilities</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Ad Network</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>- Click-Through Attribution - View-Through Attribution</td></tr><tr><td>Ad Campaign Types</td><td>- Acquisition campaigns - Retargeting campaigns</td></tr><tr><td>Ad Formats</td><td>Contact support at AppLovin for more information.</td></tr><tr><td>Click Types</td><td>- Client-side click - Server-side click</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android</td></tr><tr><td>Link Wrapping</td><td>Supported</td></tr><tr><td>Cost Ingestion Support</td><td>Supported</td></tr><tr><td>Cost Ingestion Types</td><td>API</td></tr><tr><td>Pricing Models</td><td>- CPI - CPA</td></tr></tbody></table><h2 id="_1-complete-ads-prerequisites" tabindex="-1">1. Complete Ads Prerequisites <a class="header-anchor" href="#_1-complete-ads-prerequisites" aria-label="Permalink to &quot;1. Complete Ads Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">DEVELOPER MAY BE REQUIRED</p><p>The following Ads prerequisite includes providing URI schemes and other components that may require a developer:</p><ul><li><a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>Add Deep Link Routing &amp; Required Redirects</strong></a></li></ul></div><div class="warning custom-block"><p class="custom-block-title">DEVELOPER REQUIRED</p><p>The following Ads prerequisites involve app code changes:</p><ul><li><a href="./native-sdks-overview.html"><strong>Implement the Branch SDK</strong></a></li></ul></div><h2 id="_2-retrieve-credentials" tabindex="-1">2. Retrieve Credentials <a class="header-anchor" href="#_2-retrieve-credentials" aria-label="Permalink to &quot;2. Retrieve Credentials&quot;">​</a></h2><p>Before you can enable the partner integration in your Branch dashboard, you will first need to make sure you have the following credentials available:</p><ul><li>SDK Key</li></ul><h2 id="_3-enable-the-integration" tabindex="-1">3. Enable the Integration <a class="header-anchor" href="#_3-enable-the-integration" aria-label="Permalink to &quot;3. Enable the Integration&quot;">​</a></h2><ol><li>Visit the <a href="https://dashboard.branch.io/ads" target="_blank" rel="noreferrer"><strong>Ads</strong></a> page on the Branch dashboard.</li><li>Select <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a> from the sidebar.</li><li>Search for AppLovin.</li><li>Select AppLovin provide your <strong>SDK Key</strong> and click <strong>Save &amp; Enable</strong>.</li></ol><h2 id="_4-enable-postbacks" tabindex="-1">4. Enable Postbacks <a class="header-anchor" href="#_4-enable-postbacks" aria-label="Permalink to &quot;4. Enable Postbacks&quot;">​</a></h2><p>When Branch measures a conversion (install or other event), it determines which ad network or partner is responsible for generating the action, then attributes credit to the proper partner accordingly. Branch notifies the Ad partner of these events via postbacks which are turned on when you enable any Ads integrated partner.</p><p>Basic postbacks will automatically be activated for events like Install and Purchase when you enable your ad partner.</p><p>Branch’s postback system is highly <a href="./basic-postback-configuration.html">customizable</a>; you can set up postbacks for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>You can then <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">add additional postbacks</a>, for example, if you wanted to add postbacks for custom events that are specific to your app like Account Created. You can also <a href="./branch-universal-ads-advanced.html#addingenabling-more-postbacks">edit postbacks</a> if there&#39;s additional data you really need to pass along to your ad partner.</p><p>.png &quot;Applovin_enable.png&quot;)</p><h2 id="_5-verify-integration-setup" tabindex="-1">5. Verify Integration Setup <a class="header-anchor" href="#_5-verify-integration-setup" aria-label="Permalink to &quot;5. Verify Integration Setup&quot;">​</a></h2><details><summary>View Link Parameters</summary><p>By default, Branch automatically appends partner-specific link parameters during the link creation process. When a user clicks on the link, AppLovin provides the appropriate parameter values which Branch ingests and uses for attribution and reporting purposes.</p><p>Below are the link parameters that Branch automatically appends for this ad partner:</p><p>.png &quot;Applovin_link_parameters.png&quot;)</p></details><details><summary>View Attribution Windows</summary><p>Branch employs <a href="./attribution-windows-link-settings.html">Attribution Windows</a> at both the app level and the ad partner level. When you enable AppLovin, Branch uses the attribution windows you&#39;ve selected at the app level.</p><p>However, you can choose to use the attribution windows provided specifically by AppLovin. To do so, toggle the <strong>Use Ad Partner Attribution Windows</strong> to on. Please keep in mind that only conversions attributed to this ad partner will use these specific windows; otherwise, the app-level windows prevail.</p><p>.png &quot;Applovin_Attribution_windows.png&quot;)</p></details><details><summary>Test Postbacks</summary><p>Testing your configuration is a very important step that we highly recommend you take the time to complete before going live with marketing campaigns.</p><p>Learn how to <a href="./testing-postbacks.html">Test Postbacks</a></p><p>.png &quot;Applovin_postback_testing.png&quot;)</p></details><h2 id="_6-create-a-branch-link" tabindex="-1">6. Create a Branch Link <a class="header-anchor" href="#_6-create-a-branch-link" aria-label="Permalink to &quot;6. Create a Branch Link&quot;">​</a></h2><p>If you are running paid advertising campaigns, you&#39;ll want to create a Branch Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner.</p><p>Branch Ad Links support deferred deep linking, Android App Links, and iOS Universal Links, as well as web and app conversions.</p><p>Learn how to <a href="./ad-links.html">Create A Branch Ad Link</a>.</p>',27)])])}const b=t(i,[["render",o]]);export{u as __pageData,b as default};
